import React from "react";

function TestimonialCard({ quote, name, title, company, placeholder = false }) {
  return (
    <div
      className="card"
      style={{
        padding: "2rem",
        display: "flex",
        flexDirection: "column",
        gap: "1.5rem"
      }}
    >
      {/* Quote mark */}
      <div
        aria-hidden="true"
        style={{
          fontFamily: "'Space Grotesk', sans-serif",
          fontSize: "3rem",
          lineHeight: 1,
          color: "#5B8DEF",
          opacity: 0.4,
          userSelect: "none"
        }}
      >
        "
      </div>

      {/* Quote body */}
      {placeholder ? (
        <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
          <div
            style={{
              height: "0.85rem",
              borderRadius: "0.2rem",
              background: "#252A40",
              width: "100%"
            }}
          />
          <div
            style={{
              height: "0.85rem",
              borderRadius: "0.2rem",
              background: "#252A40",
              width: "88%"
            }}
          />
          <div
            style={{
              height: "0.85rem",
              borderRadius: "0.2rem",
              background: "#252A40",
              width: "72%"
            }}
          />
          <p
            style={{
              fontFamily: "'JetBrains Mono', monospace",
              fontSize: "0.65rem",
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              color: "#3A3A5E",
              marginTop: "0.75rem"
            }}
          >
            Real quote coming
          </p>
        </div>
      ) : (
        <blockquote
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "0.95rem",
            color: "#C8C8D4",
            lineHeight: 1.7,
            fontStyle: "italic"
          }}
        >
          {quote}
        </blockquote>
      )}

      {/* Attribution */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "0.875rem",
          marginTop: "auto",
          paddingTop: "1rem",
          borderTop: "1px solid #252A40"
        }}
      >
        {/* Avatar placeholder */}
        <div
          style={{
            width: "36px",
            height: "36px",
            borderRadius: "50%",
            background: "#252A40",
            flexShrink: 0
          }}
        />

        <div>
          <p
            style={{
              fontFamily: "'Space Grotesk', sans-serif",
              fontWeight: 600,
              fontSize: "0.875rem",
              color: placeholder ? "#3A3A5E" : "#F0F0EC"
            }}
          >
            {placeholder ? "Name · Title" : name}
          </p>
          {!placeholder && (
            <p
              style={{
                fontFamily: "'JetBrains Mono', monospace",
                fontSize: "0.65rem",
                letterSpacing: "0.08em",
                color: "#8A8AB0",
                marginTop: "0.1rem"
              }}
            >
              {title} · {company}
            </p>
          )}
          {placeholder && (
            <p
              style={{
                fontFamily: "'JetBrains Mono', monospace",
                fontSize: "0.65rem",
                letterSpacing: "0.08em",
                color: "#3A3A5E"
              }}
            >
              Company
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

export default function Testimonials() {
  /* ── Swap these placeholders for real testimonials when ready ─────
     Each object: { quote, name, title, company }
     Set placeholder: false once the real text is in.
  ────────────────────────────────────────────────────────────────── */
  const testimonials = [
    {
      placeholder: true,
      quote: "",
      name: "",
      title: "",
      company: ""
    },
    {
      placeholder: true,
      quote: "",
      name: "",
      title: "",
      company: ""
    },
    {
      placeholder: true,
      quote: "",
      name: "",
      title: "",
      company: ""
    }
  ];

  return (
    <section
      id="testimonials"
      className="section"
      style={{
        paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
        paddingRight: "clamp(1.5rem, 8vw, 8rem)",
        borderTop: "1px solid #252A40"
      }}
    >
      {/* Header */}
      <div className="mb-14" style={{ maxWidth: "44ch" }}>
        <p className="eyebrow mb-4">Testimonials</p>
        <h2
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(1.8rem, 4vw, 2.8rem)",
            fontWeight: 700,
            letterSpacing: "-0.025em",
            color: "#F0F0EC",
            lineHeight: 1.1
          }}
        >
          What people say when the system ships.
        </h2>
      </div>

      {/* Grid */}
      <div
        className="grid gap-5"
        style={{
          gridTemplateColumns: "repeat(auto-fill, minmax(min(100%, 320px), 1fr))"
        }}
      >
        {testimonials.map((t, i) => (
          <TestimonialCard key={i} {...t} />
        ))}
      </div>
    </section>
  );
}
